```javascript
const canvas = document.getElementById('kaleidosketch');
const ctx = canvas.getContext('2d');

canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

const numReflections = 6;
const centerX = canvas.width / 2;
const centerY = canvas.height / 2;

let drawing = false;

canvas.addEventListener('mousedown', () => {
    drawing = true;
});

canvas.addEventListener('mouseup', () => {
    drawing = false;
    ctx.beginPath();
});

canvas.addEventListener('mousemove', (event) => {
    if (!drawing) return;

    for (let i = 0; i < numReflections; i++) {
        let angle = (2 * Math.PI / numReflections) * i;
        let x = event.clientX - centerX;
        let y = event.clientY - centerY;
        let newX = x * Math.cos(angle) - y * Math.sin(angle) + centerX;
        let newY = x * Math.sin(angle) + y * Math.cos(angle) + centerY;

        ctx.lineTo(newX, newY);
        ctx.stroke();

        newX = x * Math.cos(angle) + y * Math.sin(angle) + centerX;
        newY = -x * Math.sin(angle) + y * Math.cos(angle) + centerY;

        ctx.lineTo(newX, newY);
        ctx.stroke();
    }

    ctx.beginPath();
    ctx.moveTo(event.clientX, event.clientY);
});

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}

window.addEventListener('resize', resizeCanvas);
```
