### Update `script.js`

1. **Add color handling**: We'll use a gradient to create a color effect based on the cursor position.
2. **Update the drawing logic** to apply the color effect.

Here's the updated `script.js`:

```javascript
const canvas = document.getElementById('kaleidosketch');
const ctx = canvas.getContext('2d');

canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

const numReflections = 6;
const centerX = canvas.width / 2;
const centerY = canvas.height / 2;

let drawing = false;

canvas.addEventListener('mousedown', () => {
    drawing = true;
});

canvas.addEventListener('mouseup', () => {
    drawing = false;
    ctx.beginPath();
});

canvas.addEventListener('mousemove', (event) => {
    if (!drawing) return;

    // Create a gradient based on cursor position
    const gradient = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
    gradient.addColorStop(0, 'red');
    gradient.addColorStop(0.5, 'blue');
    gradient.addColorStop(1, 'green');

    // Calculate the angle for each reflection
    for (let i = 0; i < numReflections; i++) {
        let angle = (2 * Math.PI / numReflections) * i;
        let x = event.clientX - centerX;
        let y = event.clientY - centerY;
        let newX = x * Math.cos(angle) - y * Math.sin(angle) + centerX;
        let newY = x * Math.sin(angle) + y * Math.cos(angle) + centerY;

        ctx.strokeStyle = gradient;
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(event.clientX, event.clientY);
        ctx.lineTo(newX, newY);
        ctx.stroke();

        newX = x * Math.cos(angle) + y * Math.sin(angle) + centerX;
        newY = -x * Math.sin(angle) + y * Math.cos(angle) + centerY;

        ctx.strokeStyle = gradient;
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(newX, newY);
        ctx.lineTo(event.clientX, event.clientY);
        ctx.stroke();
    }

    ctx.beginPath();
    ctx.moveTo(event.clientX, event.clientY);
});

function resizeCanvas() {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
}

window.addEventListener('resize', resizeCanvas);
```

### Explanation of Changes

1. **Gradient Creation**:
   - A linear gradient is created using `createLinearGradient` with stops at `0`, `0.5`, and `1` to define the color transitions.

2. **Color Application**:
   - The `strokeStyle` property is set to the gradient before drawing each line segment.
   - The `lineWidth` is also adjusted to make the lines more visible.

This should give your `KaleidoSketch` demo a more dynamic and visually appealing color effect based on the cursor position. You can further customize the gradient and other properties to suit your needs.

