using System.Net.Http;
using System.Threading.Tasks;
using NAudio.Wave;
using YouTubeExtractor;

class Program
{
    static async Task Main(string[] args)
    {
        string videoId = "your_video_id_here"; // Replace with your YouTube video ID
        string outputFilePath = "output_audio.mp3"; // Output file path

        try
        {
            var videoInfo = await YouTubeExtractor.YouTubeExtractor.Default.ExtractVideoInfoAsync($"https://www.youtube.com/watch?v={videoId}");

            if (videoInfo != null && videoInfo.Videos.Any())
            {
                var audioStream = videoInfo.Videos.FirstOrDefault(v => v.AudioQuality == AudioQuality.Unknown || v.AudioQuality == AudioQuality.High);

                if (audioStream != null)
                {
                    using (var client = new HttpClient())
                    {
                        using (var response = await client.GetAsync(audioStream.Url))
                        {
                            if (response.IsSuccessStatusCode)
                            {
                                byte[] audioBytes = await response.Content.ReadAsByteArrayAsync();
                                using (WaveFileWriter waveFileWriter = new WaveFileWriter(outputFilePath, audioStream.AudioFormat))
                                {
                                    waveFileWriter.WriteData(audioBytes, 0, audioBytes.Length);
                                }
                                Console.WriteLine("Audio downloaded successfully.");
                            }
                            else
                            {
                                Console.WriteLine($"Failed to download audio. Status code: {response.StatusCode}");
                            }
