### Step 1: Create the API Endpoint

Add the following code to your theme's `functions.php` file or a custom plugin.

```php
function register_apple_sign_in_routes() {
    // Register the route for Apple Sign-In
    register_rest_route( 'apple-sign-in/v1', '/login', array(
        'methods' => 'POST',
        'callback' => 'apple_sign_in_callback',
        'permission_callback' => '__return_true', // Allow access without authentication
    ) );
}
add_action( 'rest_api_init', 'register_apple_sign_in_routes' );

function apple_sign_in_callback( $request ) {
    // Get the access token from the request
    $access_token = $request->get_param( 'access_token' );

    if ( empty( $access_token ) ) {
        return new WP_REST_Response( array( 'error' => 'Access token is required.' ), 400 );
    }

    // Verify the access token with Apple
    $url = 'https://appleid.apple.com/auth/token';
    $ch = curl_init();
    curl_setopt($ch, CURLOPT_URL, $url);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_POST, true);
    curl_setopt($ch, CURLOPT_POSTFIELDS, http_build_query(array(
        'client_id' => 'YOUR_APPLE_CLIENT_ID',
        'client_secret' => 'YOUR_APPLE_CLIENT_SECRET',
        'grant_type' => 'authorization_code',
        'code' => $access_token,
    )));

    $response = curl_exec($ch);
    curl_close($ch);

    if ( false === $response ) {
        return new WP_REST_Response( array( 'error' => 'Failed to verify token.' ), 500 );
    }

    $decoded_response = json_decode($response, true);

    if ( !isset($decoded_response['access_token']) ) {
        return new WP_REST_Response( array( 'error' => 'Invalid token response.' ), 400 );
    }

    // Use the access token to get user information from Apple
    $user_info_url = 'https://appleid.apple.com/auth/userinfo';
    $ch = curl_init();
    curl_setopt($ch, CURLOPT_URL, $user_info_url);
    curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($ch, CURLOPT_HTTPHEADER, array(
        'Authorization: Bearer ' . $decoded_response['access_token'],
    ));

    $user_info_response = curl_exec($ch);
    curl_close($ch);

    if ( false === $user_info_response ) {
        return new WP_REST_Response( array( 'error' => 'Failed to get user info.' ), 500 );
    }

    $user_info = json_decode($user_info_response, true);

    // Check if the user exists in WordPress
    $user = get_user_by( 'email', $user_info['email'] );

    if ( ! $user ) {
        // Create a new user
        $user_id = wp_create_user( $user_info['email'], wp_generate_password(), $user_info['email'] );
        if ( is_wp_error( $user_id ) ) {
            return new WP_REST_Response( array( 'error' => 'Failed to create user.' ), 500 );
        }
        $user = get_user_by( 'id', $user_id );
    } else {
        // Log in the existing user
        wp_set_current_user( $user->ID );
        wp_set_auth_cookie( $user->ID );
        do_action( 'wp_login', $user->user_login );
    }

    // Return the user data
    return new WP_REST_Response( array(
        'user_id' => $user->ID,
        'email' => $user_info['email'],
        'name' => $user_info['name'],
    ), 200 );
}
