```csharp
using System;
using System.Collections.Concurrent;
using System.Net.Http;
using Newtonsoft.Json;

public class RoutingService
{
    private readonly HttpClient _httpClient;
    private readonly ConcurrentDictionary<Tuple<double, double, double, double>, string> _cache;

    public RoutingService()
    {
        _httpClient = new HttpClient();
        _cache = new ConcurrentDictionary<Tuple<double, double, double, double>, string>();
    }

    public string GetRoute(double fromLatitude, double fromLongitude, double toLatitude, double toLongitude)
    {
        var key = Tuple.Create(fromLatitude, fromLongitude, toLatitude, toLongitude);

        if (_cache.TryGetValue(key, out string cachedResult))
        {
            return cachedResult;
        }

        string url = $"https://graphhopper.com/api/1/route?point={fromLatitude},{fromLongitude}&point={toLatitude},{toLongitude}&type=json&locale=en&vehicle=car&weighting=fastest&elevation=false&use_miles=false&layer=Omniscale";
        string result = _httpClient.GetStringAsync(url).Result;
        _cache[key] = result;

        return result;
    }
}
```
